372→    /**
373→     * This method generates a note from a sample model, or fails if invalid
374→     * @param cardIndex The index in the templates for the model. NOT `ord`
375→     */
376→    private fun getDummyCard(notetype: NotetypeJson?, cardIndex: Int, fieldValues: MutableList<String>): Card? {
377→        Timber.d("getDummyCard() Creating dummy note for index %s", cardIndex)
378→        if (notetype == null) {
379→            return null
380→        }
381→        if (mAllFieldsNull) {
382→            getLabels(fieldValues)
383→        }
384→        val n = getColUnsafe.newNote(notetype)
385→        var i = 0
386→        while (i < fieldValues.size && i < n.fields.size) {
387→            if (mAllFieldsNull) {
388→                if (mCardType != null && mCardType == getString(R.string.cloze_model_name) && i == 0 ||
389→                    mCardType == getString(R.string.basic_typing_model_name) && i == 1
390→                ) {
391→                    n.setField(i, fieldValues[i])
392→                } else {
393→                    n.setField(i, "(" + fieldValues[i] + ")")
394→                }
395→            } else {
396→                n.setField(i, fieldValues[i])
397→            }
398→            i++
399→        }
400→        try {
401→            return EphemeralCard.fromNote(n, getColUnsafe, cardIndex)
402→        } catch (e: Exception) {
403→            // Calling code handles null return, so we can log this for developer's interest but move on
404→            Timber.d(e, "getDummyCard() unable to create card")
405→        }
406→        return null
407→    }
