409→    /** Override certain aspects of Card behavior so we may display unsaved data  */
410→    inner class PreviewerCard : Card {
411→        private val mNote: Note?
412→
413→        constructor(col: Collection, id: Long) : super(col, id) {
414→            mNote = null
415→        }
416→
417→        /* if we have an unsaved note saved, use it instead of a collection lookup */ override fun note(
418→            reload: Boolean
419→        ): Note {
420→            return mNote ?: super.note(reload)
421→        }
422→
423→        /** if we have an unsaved note saved, use it instead of a collection lookup  */
424→        override fun note(): Note {
425→            return mNote ?: super.note()
426→        }
427→
428→        /** if we have an unsaved note, never return empty  */
429→        val isEmpty: Boolean
430→            get() = mNote != null
431→
432→        /** Override the method that fetches the model so we can render unsaved models  */
433→        override fun model(): NotetypeJson {
434→            return mEditedNotetype ?: super.model()
435→        }
436→
437→        override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
438→            if (renderOutput == null || reload) {
439→                val index = if (model().isCloze) {
440→                    0
441→                } else {
442→                    ord
443→                }
444→                val context = TemplateManager.TemplateRenderContext.fromCardLayout(
445→                    note(),
446→                    this,
447→                    model(),
448→                    model().getJSONArray("tmpls")[index] as JSONObject,
449→                    fillEmpty = false
450→                )
451→                renderOutput =
452→                    context.render()
453→            }
454→            return renderOutput!!
455→        }
456→    }
457→}
