459→private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
460→    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
461→        return this.renderOutput!!
462→    }
463→    companion object {
464→        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
465→            val card = EphemeralCard(col, null)
466→            card.did = 1
467→            card.ord = n.cardIndexToOrd(cardIndex)
468→
469→            val nt = n.notetype
470→            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
471→                0
472→            } else {
473→                cardIndex
474→            }
475→            val template = nt.tmpls[templateIdx] as JSONObject
476→            template.put("ord", card.ord)
477→
478→            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
479→                n,
480→                card,
481→                notetype = nt,
482→                template = template,
483→                fillEmpty = false
484→            ).render()
485→            card.renderOutput = output
486→            card.setNote(n)
487→            return card
488→        }
489→    }
490→}
