492→/** returns the number of cards from a note which has not had data saved in the database */
493→private fun Note.numberOfCardsEphemeral(): Int {
494→    // We can't use note.numberOfCards() as this uses the database value
495→    return when {
496→        this.notetype.isCloze -> col.clozeNumbersInNote(this).size
497→        else -> notetype.templatesNames.size
